#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        if (b < a && b < c) {
            printf("Bob\n");
        } else if (c < a && c < b) {
            printf("Alice\n");
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

