import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        if b < a and b < c:
            out.append('Bob')
        elif c < a and c < b:
            out.append('Alice')
        else:
            out.append('Draw')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

